248→        private void Control2Arry()
249→        {
250→            GraphFwd = BindControlsByIndex<ZedGraphControl>(this, "Graph_FWD", 4);
251→            GraphVib = BindControlsByIndex<ZedGraphControl>(this, "Graph", 3, startIndex: 5);
252→            SpecStartUpFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Spec_StartUp_FWD", 4);
253→            SpecOperatingFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Spec_Operating_FWD", 4);
254→            ValStartUpFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Val_StartUp_FWD", 4);
255→            ValOperatingFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Val_Operating_FWD", 4);
256→            DecStartUpFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Dec_StartUp_FWD", 4);
257→            DecOperatingFwd = BindControlsByIndex<System.Windows.Forms.Label>(this, "Dec_Operating_FWD", 4);
258→
259→        }
260→        private static T[] BindControlsByIndex<T>(Control root, string baseName, int count, int startIndex = 1)
261→        where T : Control
262→        {
263→            var arr = new T[count];
264→            for (int i = 0; i < count; i++)
265→            {
266→                string name = $"{baseName}{startIndex + i}";
267→                // true: 모든 자식 컨테이너까지 검색
268→                var found = root.Controls.Find(name, true).FirstOrDefault() as T;
269→                if (found == null)
270→                {
271→                    // 필요시 예외 대신 경고 로그/무시로 바꿔도 됨
272→                    throw new InvalidOperationException($"컨트롤을 찾을 수 없습니다: {name} (타입 {typeof(T).Name})");
273→                }
274→                arr[i] = found;
275→            }
276→            return arr;
277→        }
